-- promo_codes table\ncreate table if not exists promo_codes (\n  id uuid default uuid_generate_v4() primary key,\n  tenant_id uuid references tenants(id),\n  code text unique not null,\n  type text check (type in ('percent','fixed')) not null,\n  value numeric not null,\n  min_order_amount numeric,\n  usage_limit int,\n  used_count int default 0,\n  per_user_limit int,\n  expires_at timestamp,\n  is_active boolean default true,\n  created_at timestamp default now(),\n  updated_at timestamp default now()\n);\n\n-- add columns to discounts for usage limits\nalter table discounts add column if not exists usage_limit int;\nalter table discounts add column if not exists per_user_limit int;\n
